#!/usr/bin/env nvim

-- This script generates a Selene standard library definition for Neovim.
-- It uses Neovim's metadata to ensure that the core modules are recognized.

local function generate_yaml()
    local output = {
        '# This file is auto-generated by bin/generate_selene_std.lua',
        '---',
        'base: lua51',
        'globals:',
        '  vim:',
        '    any: true',
        '    fields:',
    }

    local modules = {
        'api',
        'fn',
        'lsp',
        'diagnostic',
        'loop',
        'uv',
        'keymap',
        'ui',
        'treesitter',
        'fs',
        'iter',
        'snippet',
        'secure',
        'loader',
        'mksession',
        'version',
        'health',
        'g',
        'b',
        'w',
        't',
        'v',
        'env',
        'o',
        'go',
        'bo',
        'wo',
        'opt',
        'opt_local',
        'opt_global',
        'cmd',
        'notify',
        'inspect',
        'deepcopy',
        'tbl_deep_extend',
        'tbl_extend',
        'tbl_map',
        'tbl_filter',
        'tbl_keys',
        'tbl_values',
        'list_extend',
        'schedule',
        'defer_fn',
        'wait',
        'system',
        'split',
        'trim',
        'gsplit',
    }
    table.sort(modules)
    for _, mod in ipairs(modules) do
        table.insert(output, string.format('      %s:', mod))
        table.insert(output, '        any: true')
    end

    local other_globals = {
        'Snacks',
        'jit',
        'bit',
        'describe',
        'it',
        'before_each',
        'after_each',
        'setup',
        'teardown',
        'assert',
        'stub',
        'mock',
    }
    table.sort(other_globals)
    for _, g in ipairs(other_globals) do
        table.insert(output, string.format('  %s:', g))
        table.insert(output, '    any: true')
    end

    return table.concat(output, '\n')
end

local yaml = generate_yaml()
local f = io.open('neovim.yml', 'w')
if f then
    f:write(yaml)
    f:close()
    print('Generated neovim.yml successfully')
else
    print('Failed to open neovim.yml for writing')
end
